class ExamRoom {

    public ExamRoom(int n) {
        this.n = n;
        students = new TreeMap<>();
        students.put(0, 0);
    }

    public int seat() {
        if (students.size() == 1) {
            int last = students.lastKey();
            students.put(last + (n - 1 - last) / 2, (n - 1 - last) / 2);
            return (n - 1 - last) / 2;
        }
        int prev = students.floorKey(n - 1);
        int next = students.higherKey(prev);
        int dist = (next - prev) / 2;
        if (dist == 0) {
            students.put(prev + 1, 1);
            return prev + 1;
        } else {
            students.put(prev + dist, dist);
            return prev + dist;
        }
    }

    public void leave(int p) {
        students.remove(p);
    }

    private int n;
    private TreeMap<Integer, Integer> students;
}
```

efficiency: HIGH
time complexity: O(log n) for seat() and O(1) for leave()
space complexity: O(n)
energy implications: LOW

